  ('locality-6f0ba476-moex-00377', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於不動產役權之敘述，何者錯誤？', '["不動產役權之全部或一部無存續之必要時，該不動產役權當然消滅，但限於未定期限者", "不動產役權消滅時，不動產役權人應於1個月內取回其所為之設置，否則歸屬於土地所有人", "不動產役權，除於他人之不動產，亦得就自己之不動產設定之；且不限於土地，建築物上亦得 設定之", "需役不動產之地上權人，無須經土地所有人之同意，得自行為該不動產設定不動產役權 31770 32170"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
