  ('locality-6f0ba476-moex-00380', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲夫乙妻育有丙，丙生丁女，丁與戊結婚，庚為戊之弟。下列關於親屬關係之敘述，何者錯誤？', '["甲庚間無親屬關係", "丙庚間無親屬關係", "戊為甲之四親等旁系姻親", "乙為丁之二親等直系血親"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00381', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲喪偶有一子乙。甲丙為兄弟，丙丁為夫妻。丙丁離婚後，乙丁結婚。其婚姻效力為：', '["效力未定", "得撤銷", "無效", "有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00382', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於意定監護契約之敘述，何者錯誤？', '["意定監護契約，本人委任一個或數個受任人時，均屬一個監護契約", "意定監護契約之撤回，本人或受任人一方應以由公證人作成公證書，並單獨向他方為之", "本人對受任人中一人撤回意定監護契約，須通知其他受任人，始生撤回之效力", "監護宣告後，本人暫時性恢復意思能力，得聲請法院許可終止意定監護契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00383', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於遺產清冊之敘述，何者錯誤？', '["法院得依職權命繼承人於3個月內提出遺產清冊", "繼承人中1人已開具陳報者，其他繼承人視為已陳報", "繼承人已依規定陳報，法院應依公示催告程序公告，命被繼承人之債權人報明其債權", "繼承人未於3個月內提出陳報法院者，不得主張第1148條第2項所定之利益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00384', 'locality-6f0ba476', 'locality-6f0ba476-moex-111-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲男中年喪偶，有子女乙、丙、丁。民國108年間，丙因營業資金所需，丙向甲借新臺幣（下同） 300萬元。110年間，因乙營業，甲贈與乙120萬元。甲贈與乙時，有免除該筆贈與歸扣之意思表 示。今甲死亡，除丙向甲借之300萬元，仍未返還外，甲留有積極財產900萬元。甲未留遺囑， 有關甲遺產之分割，下列敘述，何者正確？', '["丙如拋棄繼承，乙、丁均未拋棄繼承。甲之應繼遺產為900萬元，乙、丁各分得450萬元", "乙、丙、丁均未拋棄繼承。丙對甲生前未清償之300萬元，由丙之應繼分內扣還後，丙分得120 萬元", "乙如拋棄繼承，丙、丁均未拋棄繼承。丁分得600萬元", "丁如拋棄繼承，乙、丙均未拋棄繼承。乙分得450萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:04+00:00", "source_pdf_sha1": "a1087bdf06ab", "answer_pdf_sha1": "b0ca7e94525d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "314", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
